Javascript.validate:
	var value = Services.getValue(JudgmentAmount.dataBinding);
    var maxVal = 99999999.99;	     
    var err = null;
    err = validateCurrencyValue(value, maxVal, true);  /** value, max value, zero not allowed boolean **/
	if (null == err) { 
		var returnVal = WPU.formatToTwoDP(value);
		Services.setValue(JudgmentAmount.dataBinding, returnVal); }	
    return err;

