function DefaultCurrency38() {}
DefaultCurrency38.dataBinding = "/ds/EnterVariableData/curr1";
DefaultCurrency38.tabIndex = -1;
DefaultCurrency38.maxLength = 3;
DefaultCurrency38.isReadOnly = function(){return true;}
DefaultCurrency38.isTemporary = function(){return true;}
DefaultCurrency38.transformToDisplay = function(value){ return WPS.__CaseManUtils().transformCurrencySymbolToDisplay(value,null,null); }
DefaultCurrency38.transformToModel = function(value){ return WPS.__CaseManUtils().transformCurrencySymbolToModel(value,null,null); }
